import unittest
from src.order_processing import calculate_total, process_order, validate_item, InvalidItemError

class TestOrderProcessing(unittest.TestCase):

    def test_calculate_total(self):
        self.assertEqual(calculate_total([{'name': 'Item 1', 'price': 10.0}, {'name': 'Item 2', 'price': 20.0}]), 30.0)
        self.assertEqual(calculate_total([]), 0.0)

    def test_calculate_total_invalid_item(self):
        with self.assertRaises(InvalidItemError):
            calculate_total([{'name': 'Item 1'}])

    def test_process_order(self):
        result = process_order('ORD-001', [{'name': 'Item 1', 'price': 10.0}])
        self.assertEqual(result, {'order_id': 'ORD-001', 'total': 10.0, 'status': 'processed'})

    def test_validate_item(self):
        self.assertTrue(validate_item({'name': 'Item 1', 'price': 10.0}))
        self.assertFalse(validate_item({'name': 'Item 1'}))
        self.assertFalse(validate_item({'price': 10.0}))
        self.assertFalse(validate_item({'name': 123, 'price': 10.0}))

if __name__ == '__main__':
    unittest.main()

